import{_ as t,o as a,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Via API Connection","description":"","frontmatter":{"title":"Via API Connection","slug":"cost-data-via-api-connection"},"headers":[],"relativePath":"marketer-hub/cost-data-via-api-connection.md","filePath":"marketer-hub/cost-data-via-api-connection.md"}'),o={name:"marketer-hub/cost-data-via-api-connection.md"};function i(s,e,c,h,d,l){return a(),n("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Cost data can be enabled through a direct integration between Branch and the ad partner. This integration is established via an API connection that is uniquely authenticated for each partner.</p><p>Once integrated, Branch will begin to ingest cost data from the ad partner and begin to create reports in the Branch Dashboard for you to analyze campaign performance across multiple ad partners in one place.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Cost Data, you first need to:</p><ol><li><p>Create a <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enable our <a href="./packaging.html#performance-pro-tier">Performance product</a> for your Branch account.</p><ol><li>Contact your Branch account manager or our <a href="https://www.branch.io/contact-sales" target="_blank" rel="noreferrer">sales team</a> to get started.</li></ol></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-basic-integration.html">iOS</a> | <a href="./android-basic-integration.html">Android</a>).</p></li></ol><h2 id="enable-cost-data-via-api-connection" tabindex="-1">Enable cost data via API connection <a class="header-anchor" href="#enable-cost-data-via-api-connection" aria-label="Permalink to &quot;Enable cost data via API connection&quot;">​</a></h2><p>To see which ad partners Branch integrates with directly through API connection, visit the list on the <a href="https://help.branch.io/docs/roi-hub#ad-partner-support" target="_blank" rel="noreferrer">ROI Hub Overview page</a>.</p><h3 id="sans" tabindex="-1">SANs <a class="header-anchor" href="#sans" aria-label="Permalink to &quot;SANs&quot;">​</a></h3><p>For supported SANs, cost data can be enabled through their Partner Management Screen in the Branch Dashboard via the <strong>Account Settings</strong> tab.</p><p>Here, you&#39;ll connect your ad partner through their respective authentication flow (typically through a login).</p><p>Go through the login flow to authenticate your ad partner and click <strong>Save &amp; Enable.</strong></p><p><em>[Image: 267cdeb-Authenticate_SAN.png]</em>.png)</p><h3 id="non-sans" tabindex="-1">Non-SANs <a class="header-anchor" href="#non-sans" aria-label="Permalink to &quot;Non-SANs&quot;">​</a></h3><p>For supported non-SANs, cost data can be enabled through their Partner Management screen in the Branch Dashboard via the <strong>Cost Data</strong> tab.</p><p><em>[Image: ba8b97273e74d38de4eb13b68b89c6cb902d874767dd6799ba35b7876829ad27-Screenshot_2024-11-18_at_11.41.33_PM.png]</em>.png)</p><p>During setup, you will be able to input your ad partner-specific key/token/etc. to the corresponding fields to authenticate the API connection. These values can be retrieved from your ad partner account manager or through their dashboard.</p><p><strong>Note</strong>: These authentication fields will be different for each ad partner.</p><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><h3 id="data-scheduling" tabindex="-1">Data scheduling <a class="header-anchor" href="#data-scheduling" aria-label="Permalink to &quot;Data scheduling&quot;">​</a></h3><p>By default, Branch APIs will use the below general timelines for how often data is requested:</p><table tabindex="0"><thead><tr><th>Days Passed</th><th>Hours Passed</th><th>Number of Requests for a Single Day of Data</th></tr></thead><tbody><tr><td>0, 1</td><td>0-48</td><td>4 times per day</td></tr><tr><td>2, 3, 4, 5</td><td>44-144</td><td>1 time per day</td></tr><tr><td>6-20</td><td>144-504</td><td>1 time every 5 days</td></tr><tr><td>21-29</td><td>504-720</td><td>0</td></tr><tr><td>30</td><td>720</td><td>1 time</td></tr></tbody></table><p>These schedules may vary by ad partner.</p><h3 id="timezone-for-cost" tabindex="-1">Timezone for cost <a class="header-anchor" href="#timezone-for-cost" aria-label="Permalink to &quot;Timezone for cost&quot;">​</a></h3><ul><li>If the partner timezone can be edited then you can change it on their side. However, this might mean that Branch Cost numbers don’t exactly match your invoices or partner dashboard</li><li>If the partner timezone can’t be edited then you can change your Branch Dashboard timezone. However, this can cause inconsistencies with numbers and Facebook. So, this isn’t recommended.</li></ul><h3 id="connection-failures" tabindex="-1">Connection failures <a class="header-anchor" href="#connection-failures" aria-label="Permalink to &quot;Connection failures&quot;">​</a></h3><p>If your Partner Management screen for an ad partner is indicating &quot;Failed&quot; or &quot;Not receiving cost, click, impression&quot;, it is likely caused by one or more of the following:</p><ul><li>Your partner&#39;s authentication token expired. In this case, you must re-authenticate.</li><li>You have just authenticated or re-authenticated the ad partner. In this case, you must wait 24 hours for data to start flowing.</li><li>You have authenticated the wrong ad accounts that aren&#39;t running any valid campaigns with cost</li></ul><p>If you are still seeing failures, please reach out to Support or your Branch Account Manager.</p><div class="tip custom-block"><p class="custom-block-title">Email Notification</p><p>You can sign up for Branch&#39;s Notification &amp; Alerting system to get notified on changes like this. To enable, view our guide <a href="./notification-alerting-system.html">here</a>.</p></div>',30)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
